# --- In-memory stores (use a proper database in production) ---
users_db = {}
api_keys_db = {}
login_attempts = {}

MAX_LOGIN_ATTEMPTS = 5
LOCKOUT_DURATION = 300  # seconds


def _rate_limit_check(identifier):
    """Check if an identifier is rate-limited due to failed attempts."""
    now = time.time()
    if identifier in login_attempts:
        attempts, lockout_until = login_attempts[identifier]
        if lockout_until and now < lockout_until:
            return False, "Account temporarily locked due to too many failed attempts. Try again later."
        if lockout_until and now >= lockout_until:
            login_attempts[identifier] = (0, None)
    return True, None


def _record_failed_attempt(identifier):
    """Record a failed login attempt."""
    now = time.time()
    attempts, _ = login_attempts.get(identifier, (0, None))
    attempts += 1
    lockout_until = None
    if attempts >= MAX_LOGIN_ATTEMPTS:
        lockout_until = now + LOCKOUT_DURATION
        logger.warning("Account locked due to repeated failed attempts: %s", identifier)
    login_attempts[identifier] = (attempts, lockout_until)


def _clear_failed_attempts(identifier):
    """Clear failed attempts on successful login."""
    login_attempts.pop(identifier, None)


def _generate_api_key():
    """Generate a cryptographically secure API key."""
    return secrets.token_urlsafe(48)


def _hash_api_key(api_key):
    """Hash an API key for storage."""
    return hashlib.sha256(api_key.encode('utf-8')).hexdigest()


def require_auth(f):
    """Decorator to require authentication for endpoints."""
    @wraps(f)
    def decorated(*args, **kwargs):
        if not session.get('authenticated'):
            return jsonify({"error": "Authentication required"}), 401
        if session.get('mfa_pending'):
            return jsonify({"error": "MFA verification required"}), 403
        return f(*args, **kwargs)
    return decorated


def require_api_key(f):
    """Decorator to require valid API key authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        if not api_key:
            return jsonify({"error": "API key required"}), 401

        api_key_hash = _hash_api_key(api_key)
        api_key_data = None
        for key_hash, data in api_keys_db.items():
            if hmac.compare_digest(key_hash, api_key_hash):
                api_key_data = data
                break

        if not api_key_data:
            logger.warning("Invalid API key attempt")
            return jsonify({"error": "Invalid API key"}), 401

        if api_key_data.get('revoked'):
            logger.warning("Revoked API key used for user: %s", api_key_data.get('username'))
            return jsonify({"error": "API key has been revoked"}), 401

        if api_key_data.get('expires_at') and datetime.utcnow() > api_key_data['expires_at']:
            return jsonify({"error": "API key has expired"}), 401

        username = api_key_data['username']
        allowed, msg = _rate_limit_check(f"api:{username}")
        if not allowed:
            return jsonify({"error": msg}), 429

        # Validate that the user still exists and is active
        if username not in users_db:
            return jsonify({"error": "User account not found"}), 401

        if not users_db[username].get('active', True):
            return jsonify({"error": "User account is disabled"}), 401

        # Check allowed scopes
        request_scope = request.headers.get('X-API-Scope', 'read')
        allowed_scopes = api_key_data.get('scopes', ['read'])
        if request_scope not in allowed_scopes:
            return jsonify({"error": "Insufficient API key scope"}), 403

        request.api_user = username
        request.api_scopes = allowed_scopes
        return f(*args, **kwargs)
    return decorated


@app.route('/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()
    if not data:
        return jsonify({"error": "JSON body required"}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')
    enable_mfa = data.get('enable_mfa', False)

    if not username or not password:
        return jsonify({"error": "Username and password are required"}), 400

    if len(username) < 3 or len(username) > 64:
        return jsonify({"error": "Username must be between 3 and 64 characters"}), 400

    if not username.isalnum():
        return jsonify({"error": "Username must be alphanumeric"}), 400

    if len(password) < 12:
        return jsonify({"error": "Password must be at least 12 characters"}), 400

    if username in users_db:
        return jsonify({"error": "Username already exists"}), 409

    user_data = {
        'password_hash': generate_password_hash(password, method='scrypt'),
        'mfa_enabled': False,
        'mfa_secret': None,
        'active': True,
        'created_at': datetime.utcnow().isoformat(),
    }

    mfa_provisioning_uri = None
    if enable_mfa:
        mfa_secret = pyotp.random_base32()
        user_data['mfa_enabled'] = True
        user_data['mfa_secret'] = mfa_secret
        totp = pyotp.TOTP(mfa_secret)
        mfa_provisioning_uri = totp.provisioning_uri(
            name=username,
            issuer_name="SecureApp"
        )

    users_db[username] = user_data
    logger.info("User registered: %s (MFA: %s)", username, user_data['mfa_enabled'])

    response = {"message": "User registered successfully", "mfa_enabled": user_data['mfa_enabled']}
    if mfa_provisioning_uri:
        response["mfa_provisioning_uri"] = mfa_provisioning_uri
        response["message"] += ". Please configure your authenticator app with the provisioning URI."

    return jsonify(response), 201


@app.route('/login', methods=['POST'])
def login():
    """
    Login endpoint. All users go through the same authentication flow:
    1. Verify password
    2. If MFA enabled, require OTP verification before granting access
    3. If MFA not enabled, grant access after password verification
    
    There is NO way to bypass MFA if it is enabled for a user.
    """
    data = request.get_json()
    if not data:
        return jsonify({"error": "JSON body required"}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({"error": "Username and password are required"}), 400

    # Rate limiting
    allowed, msg = _rate_limit_check(username)
    if not allowed:
        return jsonify({"error": msg}), 429

    user = users_db.get(username)
    if not user:
        # Use constant-time comparison behavior to prevent timing attacks
        generate_password_hash("dummy_password", method='scrypt')
        _record_failed_attempt(username)
        return jsonify({"error": "Invalid credentials"}), 401

    if not user.get('active', True):
        return jsonify({"error": "Account is disabled"}), 403

    if not check_password_hash(user['password_hash'], password):
        _record_failed_attempt(username)
        logger.warning("Failed login attempt for user: %s", username)
        return jsonify({"error": "Invalid credentials"}), 401

    _clear_failed_attempts(username)

    if user.get('mfa_enabled'):
        # MFA is enabled - set session to pending MFA state
        # User is NOT authenticated until MFA is verified
        session.clear()
        session['username'] = username
        session['mfa_pending'] = True
        session['authenticated'] = False
        session['mfa_challenge_time'] = time.time()
        session.permanent = True
        logger.info("MFA challenge issued for user: %s", username)
        return jsonify({
            "message": "Password verified. MFA verification required.",
            "mfa_required": True
        }), 200
    else:
        # No MFA - grant access
        session.clear()
        session['username'] = username
        session['authenticated'] = True
        session['mfa_pending'] = False
        session.permanent = True
        logger.info("User logged in (no MFA): %s", username)
        return jsonify({
            "message": "Login successful",
            "mfa_required": False
        }), 200


@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    """Verify MFA OTP code. Only accessible after password verification."""
    if not session.get('mfa_pending'):
        return jsonify({"error": "No pending MFA challenge"}), 400

    username = session.get('username')
    if not username:
        session.clear()
        return jsonify({"error": "Invalid session"}), 401

    # Check MFA challenge timeout (5 minutes)
    challenge_time = session.get('mfa_challenge_time', 0)
    if time.time() - challenge_time > 300:
        session.clear()
        logger.warning("MFA challenge expired for user: %s", username)
        return jsonify({"error": "MFA challenge expired. Please login again."}), 401

    data = request.get_json()
    if not data:
        return jsonify({"error": "JSON body required"}), 400

    otp_code = data.get('otp', '').strip()
    if not otp_code:
        return jsonify({"error": "OTP code is required"}), 400

    # Validate OTP format
    if not otp_code.isdigit() or len(otp_code) != 6:
        return jsonify({"error": "Invalid OTP format"}), 400

    # Rate limiting for MFA attempts
    mfa_key = f"mfa:{username}"
    allowed, msg = _rate_limit_check(mfa_key)
    if not allowed:
        session.clear()
        return jsonify({"error": msg}), 429

    user = users_db.get(username)
    if not user or not user.get('mfa_secret'):
        session.clear()
        return jsonify({"error": "Invalid session"}), 401

    totp = pyotp.TOTP(user['mfa_secret'])
    # valid_window=1 allows for slight time drift (±30 seconds)
    if not totp.verify(otp_code, valid_window=1):
        _record_failed_attempt(mfa_key)
        logger.warning("Failed MFA attempt for user: %s", username)
        return jsonify({"error": "Invalid OTP code"}), 401

    _clear_failed_attempts(mfa_key)

    # MFA verified - grant full access
    session['authenticated'] = True
    session['mfa_pending'] = False
    session.pop('mfa_challenge_time', None)
    logger.info("User logged in with MFA: %s", username)

    return jsonify({"message": "MFA verification successful. Login complete."}), 200


@app.route('/api/generate-api-key', methods=['POST'])
@require_auth
def generate_api_key():
    """
    Generate an API key for the authenticated user.
    The user must be fully authenticated (including MFA if enabled).
    API keys are scoped and have expiration dates.
    """
    username = session.get('username')
    data = request.get_json() or {}

    scopes = data.get('scopes', ['read'])
    valid_scopes = {'read', 'write', 'admin'}
    requested_scopes = set(scopes)
    if not requested_scopes.issubset(valid_scopes):
        return jsonify({"error": f"Invalid scopes. Allowed: {valid_scopes}"}), 400

    # Default expiration: 30 days
    expires_days = min(data.get('expires_days', 30), 365)
    expires_at = datetime.utcnow() + timedelta(days=expires_days)

    api_key = _generate_api_key()
    api_key_hash = _hash_api_key(api_key)

    api_keys_db[api_key_hash] = {
        'username': username,
        'scopes': list(requested_scopes),
        'created_at': datetime.utcnow().isoformat(),
        'expires_at': expires_at,
        'revoked': False,
    }

    logger.info("API key generated for user: %s (scopes: %s, expires: %s)",
                username, requested_scopes, expires_at.isoformat())

    # Return the API key only once - it cannot be retrieved again
    return jsonify({
        "message": "API key generated. Store it securely - it cannot be retrieved again.",
        "api_key": api_key,
        "scopes": list(requested_scopes),
        "expires_at": expires_at.isoformat(),
    }), 201


@app.route('/api/revoke-api-key', methods=['POST'])
@require_auth
def revoke_api_key():
    """Revoke an API key. User must provide the key to revoke."""
    data = request.get_json()
    if not data or not data.get('api_key'):
        return jsonify({"error": "API key is required"}), 400

    api_key = data['api_key']
    api_key_hash = _hash_api_key(api_key)
    username = session.get('username')

    if api_key_hash in api_keys_db:
        if api_keys_db[api_key_hash]['username'] != username:
            return jsonify({"error": "Not authorized to revoke this key"}), 403
        api_keys_db[api_key_hash]['revoked'] = True
        logger.info("API key revoked for user: %s", username)
        return jsonify({"message": "API key revoked successfully"}), 200

    return jsonify({"error": "API key not found"}), 404


