@app.route('/enable-mfa', methods=['POST'])
@require_auth
def enable_mfa():
    """Enable MFA for the authenticated user."""
    username = session.get('username')
    user = users_db.get(username)

    if not user:
        return jsonify({"error": "User not found"}), 404

    if user.get('mfa_enabled'):
        return jsonify({"error": "MFA is already enabled"}), 400

    mfa_secret = pyotp.random_base32()
    totp = pyotp.TOTP(mfa_secret)
    provisioning_uri = totp.provisioning_uri(name=username, issuer_name="SecureApp")

    # Store temporarily until verified
    session['pending_mfa_secret'] = mfa_secret

    return jsonify({
        "message": "Scan the QR code or use the provisioning URI, then verify with an OTP.",
        "provisioning_uri": provisioning_uri,
    }), 200


@app.route('/confirm-enable-mfa', methods=['POST'])
@require_auth
def confirm_enable_mfa():
    """Confirm MFA setup by verifying an OTP code."""
    username = session.get('username')
    pending_secret = session.get('pending_mfa_secret')

    if not pending_secret:
        return jsonify({"error": "No pending MFA setup. Call /enable-mfa first."}), 400

    data = request.get_json()
    if not data or not data.get('otp'):
        return jsonify({"error": "OTP code is required"}), 400

    otp_code = data['otp'].strip()
    if not otp_code.isdigit() or len(otp_code) != 6:
        return jsonify({"error": "Invalid OTP format"}), 400

    totp = pyotp.TOTP(pending_secret)
    if not totp.verify(otp_code, valid_window=1):
        return jsonify({"error": "Invalid OTP code. MFA not enabled."}), 400

    users_db[username]['mfa_enabled'] = True
    users_db[username]['mfa_secret'] = pending_secret
    session.pop('pending_mfa_secret', None)

    logger.info("MFA enabled for user: %s", username)
    return jsonify({"message": "MFA enabled successfully"}), 200


